from agents import Agent, Runner, GuardrailFunctionOutput, RunContextWrapper
from agents.guardrail import input_guardrail, output_guardrail
from pydantic import BaseModel
import re

# Input guardrail: block messages with banned keywords
BANNED_KEYWORDS = ["competitor-product", "internal-system-name"]

@input_guardrail
async def topic_guardrail(
    context: RunContextWrapper,
    agent: Agent,
    input: str,
) -> GuardrailFunctionOutput:
    """Block requests that mention banned keywords."""
    lower = input.lower()
    for kw in BANNED_KEYWORDS:
        if kw in lower:
            return GuardrailFunctionOutput(
                output_info=f"Blocked: message contained banned keyword '{kw}'",
                tripwire_triggered=True,  # True = block the request
            )
    return GuardrailFunctionOutput(
        output_info="Passed topic check",
        tripwire_triggered=False,
    )

# Output guardrail: flag responses that look like they contain credentials
CREDENTIAL_PATTERN = re.compile(r"sk-[a-zA-Z0-9]{20,}", re.IGNORECASE)

@output_guardrail
async def credential_leak_guardrail(
    context: RunContextWrapper,
    agent: Agent,
    output,   # final agent output object
) -> GuardrailFunctionOutput:
    """Block responses that contain credential-like strings."""
    text = str(output.final_output or "")
    if CREDENTIAL_PATTERN.search(text):
        return GuardrailFunctionOutput(
            output_info="Blocked: response contained credential pattern",
            tripwire_triggered=True,
        )
    return GuardrailFunctionOutput(
        output_info="Output is safe",
        tripwire_triggered=False,
    )

# Attach guardrails to the agent
guarded_agent = Agent(
    name="GuardedAssistant",
    instructions="You are a helpful assistant.",
    tools=[],
    input_guardrails=[topic_guardrail],
    output_guardrails=[credential_leak_guardrail],
)

# Test: normal message
result = Runner.run_sync(guarded_agent, "What is the capital of France?")
print(result.final_output)  # Paris.

# Test: message with banned keyword triggers InputGuardrailTripwireTriggered
from agents.exceptions import InputGuardrailTripwireTriggered
try:
    Runner.run_sync(guarded_agent, "Tell me about competitor-product's pricing.")
except InputGuardrailTripwireTriggered as e:
    print(f"Blocked: {e}")

from agents import Agent, Runner
from agents.tracing import add_trace_processor, TracingProcessor, Trace, Span
from dataclasses import dataclass, field
import time

@dataclass
class LocalTracer(TracingProcessor):
    """Collects spans locally for debugging and testing."""
    spans: list[dict] = field(default_factory=list)

    def on_trace_start(self, trace: Trace) -> None:
        self.spans.append({
            "type": "trace_start",
            "trace_id": trace.trace_id,
            "started_at": time.time(),
        })

    def on_span_start(self, span: Span) -> None:
        self.spans.append({
            "type": "span_start",
            "span_id": span.span_id,
            "span_type": type(span).__name__,
        })

    def on_span_end(self, span: Span) -> None:
        self.spans.append({
            "type": "span_end",
            "span_id": span.span_id,
            "duration_ms": span.ended_at - span.started_at if span.ended_at else None,
        })

    def on_trace_end(self, trace: Trace) -> None:
        print(f"[Trace {trace.trace_id}] {len(self.spans)} events collected")

local_tracer = LocalTracer()
add_trace_processor(local_tracer)

agent = Agent(
    name="TracedAssistant",
    instructions="You are a helpful assistant.",
    tools=[],
)

result = Runner.run_sync(agent, "What is 2 + 2?")
print(result.final_output)
print(f"Captured {len(local_tracer.spans)} trace events")
